css:
/*【草莓总动员】作者：易碎蝶
①本美化免费发布于QQ小群，禁止二传二改，倒卖买卖同罪。
②部分代码用到了其他老师分享的，有标注~
③仅限于在正规渠道由本人发布后下载获取，一切其他方式获得皆视为二传，抓到必究*/

/* ====== 全局字体====== */
@import url("https://fontsapi.zeoseven.com/243/main/result.css");

body {
    font-family: "寒蝉半圆体";
    font-weight: normal;
}

/*————顶栏————*/
#top-bar {
    position: fixed !important;  
    overflow: visible !important;
    background: none !important;
    border: 0 !important;
    box-shadow: none !important;
    pointer-events: none;
    width: 100vw;  /*宽度*/
    height: 77px;  
    top: 0;
    left: 0;
}

#top-bar::before {
    content: "";
    position: fixed;
    background:  url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=") no-repeat center / cover;  

    /*⭕️顶栏核心 */
    top: 0px;
    left: 0px;
    right: 0px;
    bottom: 35px;/*⭕️只有这里需要改*/


    z-index: 5;
    pointer-events: auto;

    transform: none !important;
    animation: none !important;
}




/* ⭕️顶栏装饰层 */
#top-bar::after {
    content: "";
    position: fixed;
    background: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=") no-repeat center / contain;
    width: 80px;
    height: 200px;
    top: -70px;
    right: 280px;
    z-index: 6;
    pointer-events: none;
    transform-origin: top center;
}




/* —————面板背景———— */
.drawer-content {
 background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 面板背景 */
  background-size: cover; 
  background-position: center; 
  background-repeat: no-repeat; 
  background-attachment: fixed; 
}
/*移除面板圆角@曹语涵*/
.drawer-content {
  border-radius: 0;
}
.drawer-content {
  border-top-left-radius: 0;
  border-top-right-radius: 0;
}

/* ===== ⭕️楼层箭头、计数器核心 ===== */
.fa-chevron-right:before,
.fa-chevron-left:before,
.fa-arrow-right:before {
  content: "" !important;
  display: none !important; 
}

.fa-chevron-left,
.fa-chevron-right {
  display: inline-block;
  width: 30px;
  height: 30px; 
  min-width: 0;
  opacity: 1 !important; 
  background: center/contain no-repeat;
}

.fa-chevron-left {
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 左 */
  margin-bottom: -80px; 
padding: 0px 20px 0;
}
.fa-chevron-right {
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 右 */
  top: 50% !important;
  left: 0% !important;
  transform: translate(-70%, 200%) !important;
  z-index: 9999 !important;
}
/* ===== 楼层计数器样式 ===== */
.swipes-counter {
  font-size: 9px;
  font-weight: 540;
  opacity: 0.4 !important;
  color: #E98D96 !important;
}
.swipes-counter {
  position: absolute;
  top: 57px;
  right: 90px;
  z-index: 9999;
  pointer-events: none;
}

/* ==============================================
🦋气泡拼接开始🦋 *==============================================*/

/* 🍃上层装饰层、拼接气泡顶部 */
.mes::before {
  content: "";
  position: absolute;
  top: -179px; /* 【上下】(负值向上) */
  left: 0px; /* 【左右】 */
  width: 355px; /* 【宽度/大小】 */
  height: 530px; /* 【高度/大小】 */
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); 
  background-size: contain; 
  background-repeat: no-repeat; 
  z-index: -2; 
  pointer-events: none; 
}


/* 🍃 中层气泡*/
 .mes {
   z-index: -3;
  max-width: 355px;/*【🍃宽度】*/
  width: 100%;/*【👁宽度，一般调整第一个就行，没效果再调整这个】*/
  margin: 160px auto 90px;/*【AI和用户的气泡距离⭕️第一个是调整最早的消息与顶部的距离防止顶部超过屏幕】*/
  border-radius: 0px;
  background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') repeat-y; 
  background-size: 100% auto; 
  background-attachment: local; 
  transition: transform 0.2s ease; 
  transform-origin: top center;
  position: relative;
  overflow: visible;
  box-shadow: none !important; 
}
/* 🍃下层装饰层、拼接气泡尾部 */
.mes::after {
  content: "";
  position: absolute;
  bottom: -149px; /* 【上下】(负值向下) */
  right: -0px; /* 下层装饰层【左右】 */
  width: 355px; /* 【宽度/大小】 */
  height: 151px; /* 【高度/大小👁会影响最新消息的底部留白，不可调太高，宽度拉不动再调高一点】 */
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); 
background-size: contain; 
  background-repeat: no-repeat;
  z-index: -4; 
  pointer-events: none; 
}

/*——————🍃文本边距——————*/

 .mes_text,
.mes_reasoning {
    font-weight: 400; 
    line-height: 1.7; /* 行高 */
    text-align: justify; 
    text-justify: inter-word; 
    overflow-wrap: anywhere;
    hyphens: auto; 

    /* 优化后的间距系统 */
    --top-padding: 2.7rem;    /* 顶部 */
    --bottom-padding: 0rem; /* 底部 */
    --left-padding: 1.7rem;  /* 左侧 */
    --right-padding: 2.4rem; /* 右侧 */

    padding: var(--top-padding) var(--right-padding) var(--bottom-padding) var(--left-padding);
    max-width: 100ch;
    margin: 0 auto; 

    /* 高级排版增强 */
    font-kerning: normal; 
    letter-spacing: 0.01em; 
    text-rendering: optimizeLegibility; 
}

.mes_reasoning::first-letter {
    initial-letter: 2;
    font-weight: 600;
    margin-right: 0.5em;
}

/* ==============================================
🦋气泡拼接结束🍃头像美化开始============================================== */


/*⭕️头像框*/
.mesAvatarWrapper {
  position: absolute;
  top: -147px;
  left: 48.9%;
  transform: translateX(-50%);
  z-index: -1;
  width: 70px;  
  height: 70px; 
  overflow: visible; 
}

/* ⭕️头像框位置与大小调整核心 */
.mesAvatarWrapper::after {
  content: "";
  position: absolute;
  top: 0%;/* 【上下】 */
  left: 44%;/* 【左右】 */
  width: 90%;  /* 【框宽度】 */
  height: 65%; /* 【框高度】 */
  display: block;

  /* ⭕️头像框链接放置处 */
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');/*←🍃*/
  background-size: 100% 100%;
  background-repeat: no-repeat;
  background-position: center;
  transform: translate(-50%, -50%);
  z-index: 1; 

}

.mesAvatarWrapper img {
  position: relative;
  z-index: -1; 
}

/* ⭕️头像位置 */
.mesAvatarWrapper {
  position: absolute;
  top: -125px;           /* 【负值向上】 */
  left: 50%;            /* 【头像左右】 */
  transform: translateX(-50%);
  z-index: -1;
    filter: 
    saturate(1) !important;
}

/* ⭕️头像尺寸*/
.mesAvatarWrapper .avatar {
  /* 🍃头像尺寸 */
  width: 60px;           /* 宽度 */
  height: 60px;          /* 高度 */
  transform: rotate(-0deg); /* 旋转 */
}
.mesAvatarWrapper .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* ⭕user设置页面/角色选择头像美化⭕*/
/*收藏头像黄圈隐藏、名字颜色修改@Little YE*/
.character_select.is_fav .avatar {
  outline: none !important;
}
.character_select.is_fav .ch_name {
  color: #ED808B !important;
}
.avatar img {
    border: 2px solid white; /* 头像描边 */
    box-shadow: 
        inset -2px -2px 4px rgba(156, 169, 111, 0), 
        0px 0px 5px rgba(203, 16, 0, 0.4);
    filter: 
    saturate(1) !important;
transform: rotate(0deg); /* 旋转 */
}
/* user */
.avatar-container {
    position: relative; 
    border-radius: 10px;
    background: url('') center/cover, #; 
border: 0px solid #ffffff;
    color: #C59595;
    box-shadow: 
    inset -3px -3px 5px rgba(127, 127, 127,0),
    4px 4px 5px rgba(127, 127, 127,0);
    filter: 
    saturate(1) !important;
}


.avatar-container::after {
    content: '';
    position: absolute;
    top: 0px;
    right: 40px;
    width: 50px; 
    height: 50px; 
    background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/cover no-repeat; 
    transform: translate(30%, -30%); 
}
.avatar-container {
  position: relative;
  overflow: visible !important;
}
/* char */
.bogus_folder_select,
.character_select {
    position: relative;
border-radius: 10px;
    margin-bottom: 0px;
    background: url('') center/cover, #; 
border: 0px solid #ffffff;
    color: #C59595;
    box-shadow: 
    inset -3px -3px 5px rgba(127, 127, 127,0),
    4px 4px 5px rgba(127, 127, 127,0);
    filter: 
    saturate(1) !important;
}

.bogus_folder_select::after,
.character_select::after {
    content: '';
    position: absolute;
    top: 2px;
    right: 10px;
    width: 50px; 
    height: 50px; 
    background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/cover no-repeat; 
    transform: translate(20%, -30%); 
}
.bogus_folder_select,
.character_select {
  position: relative;
  overflow: visible !important;
}

/* ==============================================
🦋头像美化结束🍃文字效果美化开始============================================== */

/* === 设置选项=== */
small {
  color: #C59595 !important;
  opacity: 1;
}
.toggle-description {
    color: #C59595;
}
#completion_prompt_manager .completion_prompt_manager_header div {
    color: #C59595; /*字符*/
}

.fa-solid::before, .fa-regular::before {
    vertical-align: middle;
    text-align: center;
}

.right_menu_button {
    padding: 0px;
    filter: none;
    color: #C59595 !important; /* 更新文字颜色 */
}

/* === 预设区文字颜色 === */
/* 选中 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
  color: #C59595;
}

/* 未选 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name, 
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
  color: #F8CFD4;
}

/* 星号等标识颜色*/
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt .completion_prompt_manager_prompt_name .fa-solid {
    color: #ED808B;
}

/* 代码块 */
code, pre {
  background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/cover, #ffffff !important; /* 背景 */
  color: #CCB0B0 !important; 
  border: 0px solid #ffffff !important; 
  box-shadow: 
    inset 0px 2px 0px rgba(230, 36, 72, 0),
    0px 0px 7px rgba(230, 36, 72, 0.1);
  border-radius: 10px !important; 
line-height: 1.5; 
}


code, pre {
  position: relative;
  overflow: visible !important;
}
/* 引用气泡 */
.mes_text q {
padding: 3px 0px !important;
  background: #ffffff !important; 
border: 0px solid #ffffff !important;
box-shadow: 
    inset -2px -2px 5px rgba(230, 36, 72, 0),
    0px 0px 5px rgba(230, 36, 72, 0.2);
  border-radius: 0px 20px 20px 20px !important;
  font-weight: 300;
}


/* 引用区块 */
.mes_text blockquote, 
.mes_reasoning blockquote {
  border-left: 3px solid #FCEBEC !important; 
  background: url('') center/cover, #ffffff; /* 背景 */
  color: #C989F !important; 
  box-shadow: 
    inset -3px -3px 5px rgba(230, 36, 72, 0),
    0px 0px 5px rgba(230, 36, 72, 0.1);
  border-radius: 0px 10px 10px 0px !important; 

}
/* 斜体 */
em, i {
  background: linear-gradient(to bottom, 
    rgba(255, 255, 255, 0) 94%, 
    rgba(203, 16, 0, 0.3) 94%) !important; 
}
/* ==============================================
🦋文字效果美化结束🍃零碎美化开始============================================== */

/*—— 🍃楼层 ——*/


.mes .mesIDDisplay {
    position: fixed;
    top: 21.5px;
    left: -110px;                    /* 从左侧开始定位 */
  transform: none;            /* 移除所有变换效果 */
    z-index: 2;
    margin-top: 0px;
    text-align: left;           /* 文字左对齐 */
    width: auto;                /* 宽度自适应内容 */
    white-space: nowrap;        /* 防止文字换行 */
    padding: 0 10px;            /* 添加左右内边距 */
    display: inline-flex; 
    align-items: center;  
    gap: 2px;            /* 【左右文字间距】 */

    cursor: default;
    opacity: 1;
    font-size: calc(var(--mainFontSize) * 0.65);
    font-weight: 300;
    color: #E6A1A1;      /* 【颜料🎨】【主文字颜色】 */
}


/* 左侧文字 */
.mes .mesIDDisplay::before {
    content: var(--left-text, "Milk series "); /* 【左侧文字内容】 */
    white-space: nowrap;  
    color: var(--left-color, #E98D96); /* 【颜料🎨】【左侧文字颜色】 */
    font-weight: 300;
}

/* 右侧文字 */
.mes .mesIDDisplay::after {
    content: var(--right-text, ""); /* 【右侧文字内容】 */
    white-space: nowrap;  
    color: var(--right-color, #bcbcbc); /* 【颜料🎨】【右侧文字颜色】 */
    font-weight: 300;
}

/*—— 🍃基础信息【时间戳、角色昵称等】 ——*/

/* ⭕️消息文字上边距留白核心调整 */
.mes_block {
  position: relative;
  margin-top: -120px;  
  overflow: visible;
}

/* ⭕️角色名称核心调整 */
.mes_block .ch_name {
  position: relative;
  top:-34.5px; /* 上下 */
  left: 105px;
  max-width: calc(100% - 105px); 
  min-height: 0px;
  z-index: 10; 
 font-size: 0.55em;
  font-weight: 300;
  letter-spacing: 0.9px;
white-space: nowrap;
}


/* 角色昵称颜色 */
.mes_block .ch_name {
  color: #E39999 !important; 
  text-shadow: none !important;
  -webkit-text-stroke: 0 !important; 
}

/* 时间戳颜色 */
.timestamp {
  color: #E98D96 !important; 
  opacity: 1 !important; 
}


/* ⭕️时间戳核心调整 */
.timestamp {
  position: absolute;
  top: 78px;                /* 上下 */
  left: 135px;                /* 左右 */
  width: 300%; 
  font-size: 5px;            /* 字体大小 */
  font-weight: 400;          /* 字体粗细 */
  transform: rotate(0deg);   /* 旋转 */
  white-space: nowrap;
}

/* 左侧文字 */
.timestamp::before {
  content: "";       /*左侧文字 */
 font-size: 1em;
  color: #A2A2A2;            /* 左侧文字颜色 */
  display: inline;
  padding-right: 0px;        /* 右侧间距（分隔时间戳） */
  pointer-events: none;
}

/* 右侧文字 */
.timestamp::after {
  content: "";       /* 右侧文字 */
font-size: 1em;
  color: #A2A2A2;            /* 右侧文字颜色 */
  display: inline;
  padding-left: 0px;         /* 左侧间距（分隔时间戳） */
  pointer-events: none;
}


/* ⭕️编辑按钮核心调整 */
.mes_buttons {
  position: relative;
  top: 68px; /*上下*/
  left: -3px;/*左右*/
  z-index: 30;
  padding: 20px; 
  min-height: 36px;
  box-sizing: border-box;
  transform: rotate(0deg); /* 旋转 */
}

.mes_edit_buttons {
    display: none;
    flex-direction: row;
    column-gap: 5px;
    float: right;
    cursor: pointer;
    padding-bottom: 5px;
    filter: none; /*移除阴影*/
    transition: 0.3s ease-in-out;

    /* ⭕编辑菜单位置核心调整⭕ */
    position: relative;
    top: 120px;  /* 负数上移 | 正数下移  */
    right: 70px;   /* 负数右移 | 正数左移  */

  transform: rotate(0deg); /* 旋转 */
}
.mes_edit_down.menu_button.fa-solid.fa-chevron-down.interactable.disabled {
    filter: none !important;
}
.mes_button, .extraMesButtons>div {
cursor: pointer;
    transition: opacity 0.2s ease-in-out;
    filter: drop-shadow(0px 0px 0px #ffffff) !important;
    /* ⭕设置省略号菜单颜色 */
    color: #E98D96 !important;
opacity: 0.5 !important; 
}


/*—— 计时器&字符——*/
.mes {
  position: relative; 
}

.mes .mes_timer,
.mes .tokenCounterDisplay {
  position: fixed; 
  z-index: 3; 
  cursor: default;
opacity: 1;/*透明度*/
  white-space: nowrap; 
  font-size: calc(var(--mainFontSize) * 0.65);/*文字大小*/
  font-weight: 300;/*文字粗细*/
  padding: 0;
  top: var(--element-top, 240px);
  left: var(--element-left, 50%);
  transform: translateX(var(--element-translate, -50%));
}


/* === ⭕️计时器核心 === */
.mes .mes_timer {
  --element-top: var(--timer-top, 15px); /*【🍃计时器上下】*/
  --timer-left: -100px; /* 🍃计时器左右 */
  --timer-translate: 0; 
  text-align: left; 
  left: var(--timer-left);
  transform: translate(var(--timer-translate), -50%);

  /* 文字内容控制 */
  --timer-prefix: "memory "; /* 【🍃前缀】 */
  --timer-suffix: ""; /* 【🍃后缀】 */

  --timer-main-color: #E6A1A1; /* 【🍃计时器颜色】 */
  --timer-prefix-color: #E98D96; /* 【🍃前缀颜色】 */
  --timer-suffix-color: #bcbcbc; /* 【🍃后缀颜色】 */

  color: var(--timer-main-color);
}

/* 计时器文字控制 */
.mes .mes_timer::before {
  content: var(--timer-prefix); /* 前缀文字 */
  color: var(--timer-prefix-color);
  padding-right: 0px;
}
.mes .mes_timer::after {
  content: var(--timer-suffix); /* 后缀文字 */
  color: var(--timer-suffix-color);
  padding-left: 0px;
}

/* === 字符计数器单独设置 === */
.mes .tokenCounterDisplay {
  text-align: left;
  --element-top: var(--counter-top, 1px); /* 【🍃字符计数器上下】 */
  --element-left: var(--counter-left, -143%); /* 【🍃字符计数器左右】 */
  --element-translate: var(--counter-translate, -0%); 

  --counter-prefix: "Strawberry guava "; /* 【🍃前缀】 */
  --counter-suffix: ""; /* 【🍃后缀】 */

  --counter-main-color: #E6A1A1; /* 【🍃计数器颜色】 */
    --counter-prefix-color: #E98D96; /* 【🍃前缀颜色】 */
  --counter-suffix-color: #bcbcbc; /* 【🍃后缀颜色】 */
  color: var(--counter-main-color);

}

.mes .tokenCounterDisplay::before {
  content: var(--counter-prefix); /* 前缀文字 */
  color: var(--counter-prefix-color);
  padding-right: 0px;
}
.mes .tokenCounterDisplay::after {
  content: var(--counter-suffix); /* 后缀文字 */
  color: var(--counter-suffix-color);
  padding-left: 0px;
}
/*—— ⭕️外显思维链 ——*/
