  background: 
    linear-gradient(to right, #E0B9B5, rgba(252, 235, 241, 1)),
    url('https://example.com/background.jpg') center/cover;
  box-shadow: 
    inset 4px 3px 7px rgba(203, 16, 0, 0.2),
